############################################################ # PG Setup Code ############################################################ ($a, $b) = random_coprime([2..9],[2..9]); @ORCCA_variables = grep {!/[eoEOU]/} ('a' .. 'z', 'A' .. 'Z'); $var = list_random(@ORCCA_variables); Context("Form")->variables->are($var=>'Real'); $f = Compute("$a**2 $var^2 - 2*$a*$b $var + $b**2")->reduce; $answer = Compute("($a $var - $b)^2");
############################################################ # Body ############################################################
BEGIN_PGML Factor the polynomial. It is important to try to recognize a special pattern can be used. If you factor these using another method, you are missing the opportunity to practice learning the special patterns.
[`[$f]`]
[_]{$answer}{16}
END_PGML
